for (const entry of entries) {
  if (!entry.isDirectory() || !entry.name.startsWith('gad-')) continue;
  const dir = path.join(skillsRoot, entry.name);
  const skillFile = path.join(dir, 'SKILL.md');
  const metaFile = path.join(dir, 'skill.json');
  if (!fs.existsSync(metaFile)) { skipped++; continue; }
  if (!fs.existsSync(skillFile)) { problems.push(`${entry.name}: skill.json without SKILL.md`); continue; }

  let meta;
  try { meta = JSON.parse(fs.readFileSync(metaFile, 'utf8')); }
  catch (e) { problems.push(`${entry.name}: skill.json unparseable`); continue; }

  const commandPath = meta.commandPath;
  if (!commandPath) { problems.push(`${entry.name}: no commandPath`); continue; }

  const workflowRef = `workflows/${commandPath}`;
  const absWorkflow = path.join(workflowRef);
  if (!fs.existsSync(absWorkflow)) {
    problems.push(`${entry.name}: workflow ${workflowRef} does not exist`);
    continue;
  }

  const raw = fs.readFileSync(skillFile, 'utf8');
  if (/^workflow:\s*.+/m.test(raw)) {
    // already has workflow key; just delete skill.json
    fs.unlinkSync(metaFile);
    migrated++;
    continue;
  }

  const fmMatch = raw.match(/^(---\s*\r?\n)([\s\S]*?)(\r?\n---\s*(?:\r?\n|$))/);
  if (!fmMatch) { problems.push(`${entry.name}: SKILL.md has no frontmatter`); continue; }

  const newFm = `${fmMatch[1]}${fmMatch[2]}\nworkflow: ${workflowRef}${fmMatch[3]}`;
  const rest = raw.slice(fmMatch[0].length);
  fs.writeFileSync(skillFile, newFm + rest);
  fs.unlinkSync(metaFile);
  migrated++;
}

console.log(`migrated=${migrated} skipped=${skipped} problems=${problems.length}`);
for (const p of problems) console.log(`  - ${p}`);
