function readCommandBackedSkillContent(record) {
  // Decision gad-190 body-source precedence:
  //   1. COMMAND.md (legacy — still honored during transition)
  //   2. workflowFile (resolved `workflow:` frontmatter pointer)
  //   3. SKILL.md fallback
