  try {
    execSync(`git mv "${commandFile}" "${canonicalPath}"`, { stdio: 'pipe' });
  } catch (e) {
    problems.push(`${id}: git mv failed: ${e.message}`);
    continue;
  }

  // Inject workflow: frontmatter
  const raw = fs.readFileSync(skillFile, 'utf8');
  if (/^workflow:\s*.+/m.test(raw)) {
    moved++;
    continue;
  }
  const fmMatch = raw.match(/^(---\s*\r?\n)([\s\S]*?)(\r?\n---\s*(?:\r?\n|$))/);
  if (!fmMatch) { problems.push(`${id}: SKILL.md has no frontmatter`); continue; }
  const newFm = `${fmMatch[1]}${fmMatch[2]}\nworkflow: ${canonicalPath}${fmMatch[3]}`;
  const rest = raw.slice(fmMatch[0].length);
  fs.writeFileSync(skillFile, newFm + rest);
  moved++;
}

console.log(`moved=${moved} skipped=${skipped} problems=${problems.length}`);
